import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function LoginPage() {
  const [form, setForm] = useState({ username: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form.username, form.password);
      toast.success('Acceso autorizado.');
      navigate('/panel');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Credenciales incorrectas.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #060f1e 0%, #0d1f3c 60%, #0a1628 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '1rem',
      position: 'relative',
      overflow: 'hidden',
    }}>
      {/* Decorative lines */}
      <div style={{
        position: 'absolute', inset: 0, opacity: 0.04,
        backgroundImage: 'repeating-linear-gradient(0deg, transparent, transparent 80px, rgba(201,168,76,1) 80px, rgba(201,168,76,1) 81px), repeating-linear-gradient(90deg, transparent, transparent 80px, rgba(201,168,76,1) 80px, rgba(201,168,76,1) 81px)',
        pointerEvents: 'none',
      }} />

      <div style={{ width: '100%', maxWidth: '420px', position: 'relative' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '2.5rem' }}>
          <div style={{
            display: 'inline-block',
            background: 'rgba(201,168,76,0.1)',
            border: '1px solid rgba(201,168,76,0.3)',
            borderRadius: '4px',
            padding: '0.5rem 1.25rem',
            marginBottom: '1.25rem',
          }}>
            <span style={{ fontFamily: 'IBM Plex Mono, monospace', fontSize: '0.75rem', color: 'var(--gold)', letterSpacing: '0.15em' }}>
              SISTEMA OFICIAL
            </span>
          </div>
          <h1 style={{ fontFamily: 'Playfair Display, serif', fontSize: '2.8rem', color: 'var(--gold)', letterSpacing: '0.08em', lineHeight: 1 }}>
            MONUR-10
          </h1>
          <p style={{ color: 'var(--silver)', fontSize: '0.8rem', letterSpacing: '0.12em', textTransform: 'uppercase', marginTop: '0.5rem' }}>
            Modelo de Naciones Unidas Regional 10
          </p>
        </div>

        {/* Card */}
        <div className="card" style={{ border: '1px solid rgba(201,168,76,0.25)' }}>
          <div className="card-header">
            <div className="card-title">Acceso al Panel Administrativo</div>
            <p style={{ color: 'var(--silver)', fontSize: '0.8rem', marginTop: '0.25rem' }}>
              Secretarios de Proyectos y SGA Regional
            </p>
          </div>

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Usuario</label>
              <input
                type="text"
                placeholder="Ej: admin_1001"
                value={form.username}
                onChange={e => setForm({ ...form, username: e.target.value })}
                required
                autoComplete="username"
              />
            </div>
            <div className="form-group">
              <label>Contrasena</label>
              <input
                type="password"
                placeholder="Ingrese su contrasena"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                autoComplete="current-password"
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary"
              style={{ width: '100%', justifyContent: 'center', padding: '0.75rem', fontSize: '0.9rem', marginTop: '0.5rem' }}
              disabled={loading}
            >
              {loading ? <><div className="spinner" style={{ width: 16, height: 16 }} /> Verificando...</> : 'Ingresar al Sistema'}
            </button>
          </form>

          <div className="divider" />
          <div style={{ textAlign: 'center' }}>
            <a href="/checkin" style={{ fontSize: '0.8rem', color: 'var(--silver)' }}>
              Ir al Check-In de Delegados
            </a>
            <span style={{ color: 'var(--border-strong)', margin: '0 0.5rem' }}>|</span>
            <a href="/registro-voluntario" style={{ fontSize: '0.8rem', color: 'var(--silver)' }}>
              Registro de Voluntarios
            </a>
          </div>
        </div>

        <p style={{ textAlign: 'center', color: 'var(--silver)', fontSize: '0.72rem', marginTop: '1.5rem', letterSpacing: '0.06em' }}>
          REGIONAL EDUCATIVA 10 — REPUBLICA DOMINICANA
        </p>
      </div>
    </div>
  );
}
